describe('notification ordering', () => {
  it('should deliver notifications in the order events are emitted', async () => {
    const createdEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    // Emit both events sequentially — order:created first, then status change
    await eventBus.emit(createdEvent);
    await eventBus.emit(statusEvent);

    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(2);
    // order_confirmation must arrive before order_status_update
    expect(notifications[0]?.payload.type).toBe('order_confirmation');
    expect(notifications[1]?.payload.type).toBe('order_status_update');
  });

  it('should complete notification delivery before emit resolves', async () => {
    const event: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // After emit resolves, notification should already be recorded and sent
    const notifications = service.getNotifications();
    expect(notifications).toHaveLength(1);
    expect(notifications[0]?.status).toBe('sent');
  });
});

